package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair9221DifferenceFindingTest {

    private final ClonePair9221 subject = new ClonePair9221();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnSourceGuidedInput() {
        Object[] inputs = new Object[]{new byte[]{-1}, 1};
        InvocationOutcome method1Outcome = capture(values -> subject.method1((byte[]) values[0], ((Integer) values[1]).intValue()), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2((byte[]) values[0], ((Integer) values[1]).intValue()), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "char[][\u00ff]",
            null,
            "java.lang.Object[][byte[][-1],Integer(1)]",
            "java.lang.Object[][byte[][-1],Integer(1)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "char[][\uffff]",
            null,
            "java.lang.Object[][byte[][-1],Integer(1)]",
            "java.lang.Object[][byte[][-1],Integer(1)]"
        );
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
